#include <aie_api/aie.hpp>
void vec_add(input_window_int16* in0, input_window_int16* in1, output_window_int16* out) {
  for (int i = 0; i < 32; i += 16) {
    aie::vector<int16, 16> a = window_readincr_v<16>(in0);
    aie::vector<int16, 16> b = window_readincr_v<16>(in1);
    aie::vector<int16, 16> c = a + b;
    window_writeincr(out, c);
  }
}
